    try:
        A = sp.Matrix(A)
        B = sp.Matrix(B)
        C = sp.Matrix(C)
        D = sp.Matrix(D)
    except Exception:
        return False

    # all must be square and same size
    if A.shape[0] != A.shape[1]:
        return False
    n = A.shape[0]
    if B.shape != (n, n) or C.shape != (n, n) or D.shape != (n, n):
        return False

    zero = sp.zeros(n)
    I = sp.eye(n)

    # Helper for robust matrix zero/equality check
    def is_zero_matrix(M):
        return (M - sp.zeros(*M.shape)).equals(sp.zeros(*M.shape))

    def equals_identity(M):
        return (M - I).equals(sp.zeros(n))

    # Check premises:
    # AB^T symmetric: AB^T == (AB^T)^T  <=> AB^T - BA^T == 0
    M1 = A * B.T
    if not is_zero_matrix(M1 - M1.T):
        return False

    # CD^T symmetric
    M2 = C * D.T
    if not is_zero_matrix(M2 - M2.T):
        return False

    # AD^T - BC^T = I
    M3 = A * D.T - B * C.T
    if not equals_identity(M3):
        return False

    # Conclusion to verify: A^T D - C^T B = I
    M4 = A.T * D - C.T * B
    return equals_identity(M4)

